INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$69b8e79b-013d-4c16-9577-b8513ac68f17$tag$, $tag$2026012600175$tag$, $tag$ORUAM (5585986576128)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Oi, já preenchi meus dados na página Teologia EAD e quero mais informações.","time":"26/01/2026 14:50:23"},{"role":"client","text":"Por favor aguarde, em breve uma das nossas Consultoras lhe passará todas as informações.","time":"26/01/2026 14:50:23"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"26/01/2026 15:19:56"},{"role":"agent","text":"*Karina Pimentel:* A nossa *Graduação em Teologia EAD* é Bacharelado reconhecido pelo MEC ( *bit.ly/3LlEgJS* ), com a duração de 3 anos.\n\nNo formato EAD, as aulas são ao vivo e gravadas e ficam à disposição do aluno no Ambiente Virtual de Aprendizagem, para assistir no seu tempo. As aulas ao vivo terão dia e horário definidos previamente e poderão ser assistidas posteriormente, pois ficarão gravadas.\n\nO aluno tem acesso aos materiais disponibilizados por nossos professores, tem encontros remotos com tutores, através da Plataforma Virtual da FICV (Plataforma Moodle), além de contar com materiais de apoio acadêmico-científico.","time":"26/01/2026 15:20:21","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* Graduação EAD em Teologia por apenas R$ 399,70/mês! 🤩 Aproveite a condição especial: 10% de desconto na pontualidade durante toda a graduação, reduzindo o valor para R$ 359,73 por mês! 🎉 Usando o cupom *BOLSA10*\n\n✨ Sem taxa de matrícula! A primeira mensalidade é paga no ato da inscrição, e a próxima apenas no mês de início das aulas.\n\n💥 Valor promocional: Semestralidade por R$ 2.158,38!\n\n⚠ Atenção: O valor mensal pode variar de acordo com a data de matrícula:\n\nMatrículas realizadas até em JANEIRO: 6 mensalidades de R$ 359,73 = R$ 2.158,38\nMatrículas realizadas até em FEVEREIRO: 5 mensalidades de R$ 431,67 = R$2.158,38\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 539,59 = R$ 2.158,38\n\n🗓️ Início das aulas: Fevereiro de 2026 📚💻","time":"26/01/2026 15:20:42","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:*   Bom dia! Ficou alguma dúvida? O que está faltando para você dar esse passo e ingressar no curso? Tenho certeza de que será transformador em sua vida. 😊","time":"27/01/2026 08:33:51","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Atendimento Finalizado!\n\nORUAM, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"27/01/2026 18:21:26"},{"role":"client","text":"Sua sessão irá expirar em 2 minutos!","time":"29/01/2026 15:17:57"},{"role":"client","text":"Sua sessão expirou!","time":"29/01/2026 15:19:59"}]$tag$, $tag$2026-01-26 14:50:23+00$tag$, FALSE, FALSE, 6.6, $tag$2026-03-01 16:46:57.607947+00$tag$, 7, 10, 5, 2, 9, 3, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$52185473-9ccc-4e6e-9e85-d3188a244b74$tag$, $tag$2026012600177$tag$, $tag$Prof. Elton Barreto (5585997533064)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"26/01/2026 14:53:45"},{"role":"client","text":"🌟 Boa tarde Prof. Elton Barreto! Que alegria ter você aqui com a gente! 🙌","time":"26/01/2026 14:53:46"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"26/01/2026 14:53:50"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"26/01/2026 14:53:54"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"26/01/2026 14:54:01"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"26/01/2026 14:54:14"},{"role":"client","text":"Olá! Prof. Elton Barreto!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"26/01/2026 14:54:15"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"26/01/2026 14:54:19"},{"role":"client","text":"Saber sobre os cursos","time":"26/01/2026 14:54:33"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"26/01/2026 14:54:37"},{"role":"client","text":"Pós-Graduação","time":"26/01/2026 14:54:53"},{"role":"client","text":"Esses são os cursos de *Pós-Graduação* que temos disponíveis no momento:","time":"26/01/2026 14:54:57"},{"role":"client","text":"Educação Cristã Clássica","time":"26/01/2026 14:55:30"},{"role":"client","text":"Formação exclusiva para educadores e líderes que desejam ensinar com base na tradição cristã clássica.\n\n 📚 Cosmovisão cristã sólida\n 📌 Leituras fundamentais do pensamento ocidental\n 🧭 Formação para escolas cristãs ou ministérios educacionais\n 🗓️ Matrículas abertas para agosto","time":"26/01/2026 14:55:31"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"26/01/2026 14:55:36"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"26/01/2026 14:55:57"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"26/01/2026 14:55:58"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"26/01/2026 15:32:47"},{"role":"agent","text":"*Karina Pimentel:* *Pós-graduação em Educação Cristã Clássica*.\n\n*NOTA MÁXIMA NO MEC*\nPós-graduação com a maior avaliação junto ao MEC, conceito 05 estrelas.\n\n*DURAÇÃO*\nO curso tem duração de 16 meses.\n\n*CARGA HORÁRIA*\nNossa carga horária é de 400h.\n\n*DISCIPLINAS*\nContamos com um total de 10 disciplinas.\n\n*AULAS*\nO curso é totalmente on-line e você pode assistir às aulas em qualquer dia e horário, pois ficarão gravadas dentro da plataforma.\n\n*AVALIAÇÕES*\nAs avaliações serão realizadas através de questões abertas, fechadas, fóruns e elaboração de textos. Todas as atividades serão realizadas dentro da plataforma educacional, assim, não é necessário ter um Polo da Faculdade em sua cidade.\n\n*NÃO É NECESSÁRIO TCC*\nDe acordo com a nova deliberação do MEC, a Resolução CNE/CES nº 1/2018, não há mais a obrigação de entrega de um TCC.","time":"26/01/2026 15:33:30","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* O valor de investimento na Pós-graduação em Educação Cristã Clássica está em 16 mensalidades de *R$ 479,16*. \n\nNão temos taxa de matrícula. Ao pagar a primeira mensalidade hoje, as próximas serão devidas a partir do início das aulas, previsto para Abril de 2026!","time":"26/01/2026 15:33:57","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* Estamos com uma oferta especial essa semana, 20% de desconto nas mensalidades! 🤩\nMensalidades ficarão no valor de R$ 383,33.\nVamos garantir a sua vaga? 😊","time":"26/01/2026 15:34:04","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"agent","text":"*Karina Pimentel:* 🎁 Cupom de Desconto ECC: BOLSA20\n\n📌 Realize sua matrícula no link: bit.ly/InscricaoPosECC2024\n\n✅ Assim que você preencher os seus dados, o sistema disponibilizará o seu contrato para aceitação e o pagamento da primeira parcela, que pode ser feito por cartão ou boleto.","time":"26/01/2026 15:34:20","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:*   Bom dia! Ficou alguma dúvida? O que está faltando para você dar esse passo e ingressar no curso? Tenho certeza de que será transformador em sua vida. 😊","time":"27/01/2026 08:33:56","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Atendimento Finalizado!\n\nProf. Elton Barreto, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"27/01/2026 18:21:36"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"27/01/2026 18:21:37"},{"role":"client","text":"Prof. Elton Barreto, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"27/01/2026 18:36:38"}]$tag$, $tag$2026-01-26 14:53:45+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:46:57.607947+00$tag$, 10, 10, 10, 2, 9, 5, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$9a65b6a7-9fb6-42cf-8eb1-d71ac80249a9$tag$, $tag$2026012600181$tag$, $tag$Elvira Lima (5538999150055)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Oii","time":"26/01/2026 14:59:40"},{"role":"client","text":"🌟 Boa tarde Elvira Lima! Que alegria ter você aqui com a gente! 🙌","time":"26/01/2026 14:59:41"},{"role":"client","text":"Boa tarde","time":"26/01/2026 14:59:43"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"26/01/2026 14:59:44"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"26/01/2026 14:59:48"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"26/01/2026 14:59:53"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"26/01/2026 14:59:59"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"26/01/2026 15:00:05"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"26/01/2026 15:00:06"},{"role":"client","text":"Gostaria de saber o valor da pós em Educação Clássica","time":"26/01/2026 15:00:06"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"26/01/2026 15:00:07"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"26/01/2026 15:00:08"},{"role":"client","text":"Sim, concordo","time":"26/01/2026 15:00:40"},{"role":"client","text":"✅ Obrigado, Elvira Lima! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"26/01/2026 15:00:41"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"26/01/2026 15:00:46"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"26/01/2026 15:01:05"},{"role":"client","text":"Olá! Elvira Lima!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"26/01/2026 15:01:07"},{"role":"client","text":"Gostaria de saber o valor da pós em Educação Clássica","time":"26/01/2026 15:01:08"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"26/01/2026 15:01:09"},{"role":"client","text":"Saber sobre os cursos","time":"26/01/2026 15:01:59"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"26/01/2026 15:02:04"},{"role":"client","text":"Pós-Graduação","time":"26/01/2026 15:02:15"},{"role":"client","text":"Esses são os cursos de *Pós-Graduação* que temos disponíveis no momento:","time":"26/01/2026 15:02:19"},{"role":"client","text":"Educação Cristã Clássica","time":"26/01/2026 15:03:46"},{"role":"client","text":"Formação exclusiva para educadores e líderes que desejam ensinar com base na tradição cristã clássica.\n\n 📚 Cosmovisão cristã sólida\n 📌 Leituras fundamentais do pensamento ocidental\n 🧭 Formação para escolas cristãs ou ministérios educacionais\n 🗓️ Matrículas abertas para agosto","time":"26/01/2026 15:03:47"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"26/01/2026 15:03:50"},{"role":"client","text":"Quero saber valores","time":"26/01/2026 15:06:29"},{"role":"client","text":"Desculpe, não entendi a opção desejada.\nPor favor, selecione no menu abaixo a opção que mais adequa a sua necessidade.","time":"26/01/2026 15:06:30"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"26/01/2026 15:06:34"},{"role":"client","text":"Vi que tá 50% de desconto","time":"26/01/2026 15:06:38"},{"role":"client","text":"Desculpe, não entendi a opção desejada.\nPor favor, selecione no menu abaixo a opção que mais adequa a sua necessidade.","time":"26/01/2026 15:06:39"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"26/01/2026 15:06:44"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"26/01/2026 15:06:46"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"26/01/2026 15:06:47"},{"role":"client","text":"Quero saber os valores do curso de pós de educação clássica infantil","time":"26/01/2026 15:14:06"},{"role":"client","text":"Cristã *","time":"26/01/2026 15:18:26"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"26/01/2026 15:34:22"},{"role":"agent","text":"*Karina Pimentel:* *Pós-graduação em Educação Cristã Clássica*.\n\n*NOTA MÁXIMA NO MEC*\nPós-graduação com a maior avaliação junto ao MEC, conceito 05 estrelas.\n\n*DURAÇÃO*\nO curso tem duração de 16 meses.\n\n*CARGA HORÁRIA*\nNossa carga horária é de 400h.\n\n*DISCIPLINAS*\nContamos com um total de 10 disciplinas.\n\n*AULAS*\nO curso é totalmente on-line e você pode assistir às aulas em qualquer dia e horário, pois ficarão gravadas dentro da plataforma.\n\n*AVALIAÇÕES*\nAs avaliações serão realizadas através de questões abertas, fechadas, fóruns e elaboração de textos. Todas as atividades serão realizadas dentro da plataforma educacional, assim, não é necessário ter um Polo da Faculdade em sua cidade.\n\n*NÃO É NECESSÁRIO TCC*\nDe acordo com a nova deliberação do MEC, a Resolução CNE/CES nº 1/2018, não há mais a obrigação de entrega de um TCC.","time":"26/01/2026 15:34:40","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* O valor de investimento na Pós-graduação em Educação Cristã Clássica está em 16 mensalidades de *R$ 479,16*. \n\nNão temos taxa de matrícula. Ao pagar a primeira mensalidade hoje, as próximas serão devidas a partir do início das aulas, previsto para Abril de 2026!","time":"26/01/2026 15:34:51","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* Estamos com uma oferta especial essa semana, 20% de desconto nas mensalidades! 🤩\nMensalidades ficarão no valor de R$ 383,33.\nVamos garantir a sua vaga? 😊","time":"26/01/2026 15:34:59","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Vi uma publicação de 50%","time":"26/01/2026 15:42:32"},{"role":"client","text":"Arquivo de imagem | (https://igrejabatista.widechat.com.br/config/storage/view/6977b5b5be75ea59330fa2ca)","time":"26/01/2026 15:43:01"},{"role":"agent","text":"*Karina Pimentel:* Boa noite!","time":"26/01/2026 18:20:49","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Isso mesmo, descontos de até 50%.","time":"26/01/2026 18:20:58","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Fechando até sexta feira eu consigo um desconto de 50%!","time":"26/01/2026 18:21:17","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Mensalidades ficarão no valor de R$ 239,58.","time":"26/01/2026 18:22:58","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:*   Bom dia! Ficou alguma dúvida? O que está faltando para você dar esse passo e ingressar no curso? Tenho certeza de que será transformador em sua vida. 😊","time":"27/01/2026 08:38:27","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Estou aguardando se um grupo de curso que participei vai conseguir desconto","time":"27/01/2026 08:39:39"},{"role":"client","text":"O Pastor Brotto deve estar articulando","time":"27/01/2026 08:40:08"},{"role":"client","text":"Vocês tem formatura no final do curso?","time":"27/01/2026 08:40:28"},{"role":"agent","text":"*Karina Pimentel:* Benção!","time":"27/01/2026 09:42:37","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Tem sim! Ead ou Presencial se preferir!","time":"27/01/2026 09:42:57","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Presencial é em qual cidade ?","time":"27/01/2026 09:43:32"},{"role":"client","text":"Arquivo de áudio | (https://igrejabatista.widechat.com.br/config/storage/view/6978b3371338f55a7a0ea299)","time":"27/01/2026 09:44:39"},{"role":"agent","text":"*Karina Pimentel:* João Pessoa","time":"27/01/2026 09:56:20","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Educação Cristã somente Ead.","time":"27/01/2026 09:56:54","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Se a senhora se inscrever e tiver desconto maior, podemos alterar sim!","time":"27/01/2026 09:57:34","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Arquivo de imagem | (https://igrejabatista.widechat.com.br/config/storage/view/6978bc481f9cd8e83e00789a) | Ontem tentei me inscrever por um link que eu tinha e apareceu isso","time":"27/01/2026 10:23:20"},{"role":"client","text":"Como se eu tivesse uma dívida","time":"27/01/2026 10:23:25"},{"role":"client","text":"Mas nunca me inscrevi em outro curso de vocês","time":"27/01/2026 10:23:37"},{"role":"agent","text":"*Karina Pimentel:* Vou lhe transferir na Secretaria, para ser verificado ok!","time":"27/01/2026 10:26:34","feedback":"🚩 Fechamento Ausente: O contato está terminando. Sempre faça um convite para o próximo passo."},{"role":"client","text":"Karina Pimentel transferiu o atendimento para a equipe FICV - SECRETARIA","time":"27/01/2026 10:26:41"},{"role":"client","text":"Tyago Mendes transferiu o atendimento para a equipe FICV - PÓS EDUCAÇÃO CRISTÃ CLASSICA","time":"27/01/2026 10:27:31"},{"role":"client","text":"Aguarde só um momento!\n\nNeste instante, todos os nossos consultores estão prestando atendimento, o que pode gerar uma pequena espera.\n\nEstamos dedicando total atenção aos clientes que estão à sua frente. Assim que o próximo atendente estiver livre, ele irá assumir o seu chamado imediatamente.\n\nPedimos a sua compreensão e agradecemos por aguardar!","time":"27/01/2026 10:27:32"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Joyce Henrique","time":"27/01/2026 15:45:00"},{"role":"client","text":"*Joyce Henrique:* Boa tarde! A tutoria está funcionando em apenas um turno, visto que o tutor da manhã está de férias. E ontem não houve atendimento, por isso a sua espera. Mas estou à disposição para ajudar.","time":"27/01/2026 15:45:06"},{"role":"client","text":".","time":"27/01/2026 15:47:05"},{"role":"client","text":"*Joyce Henrique:* Entendi. ","time":"27/01/2026 15:47:37"},{"role":"client","text":"*Joyce Henrique:* Demandas financeiras são tratadas com a secretaria. ","time":"27/01/2026 15:47:47"},{"role":"client","text":"*Joyce Henrique:* Vou transferir esta conversa, certo? ","time":"27/01/2026 15:47:57"},{"role":"client","text":"Sim","time":"27/01/2026 16:43:46"},{"role":"client","text":"Joyce Henrique transferiu o atendimento para a equipe FICV - SECRETARIA","time":"27/01/2026 16:45:56"},{"role":"client","text":"?","time":"27/01/2026 16:46:24"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Tyago Mendes","time":"27/01/2026 17:03:49"},{"role":"client","text":"*Tyago Mendes:* Boa tarde, senhora","time":"27/01/2026 17:03:58"},{"role":"client","text":"*Tyago Mendes:* já fiz o ajuste no sistema, vou lhe transferir para o setor de relacionamento lhe orientar na sua matrícula.\n\nElas vão lhe encaminhar um novo link de inscrição","time":"27/01/2026 17:04:27"},{"role":"client","text":"Tyago Mendes transferiu o atendimento para a equipe FICV - COMERCIAL","time":"27/01/2026 17:04:40"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Thayanne Sales","time":"27/01/2026 17:06:39"},{"role":"client","text":"*Thayanne Sales:* Qual o curso que deseja informações ?","time":"27/01/2026 17:07:16"},{"role":"client","text":"*Thayanne Sales:* Olá Bom dia!","time":"28/01/2026 08:18:59"},{"role":"client","text":"*Thayanne Sales:* No que posso lhe ajudar?","time":"28/01/2026 08:19:04"},{"role":"client","text":"?","time":"28/01/2026 08:28:51"},{"role":"client","text":"*Thayanne Sales:* Qual o curso que quer se matricular?","time":"28/01/2026 08:45:40"},{"role":"client","text":"*Thayanne Sales:* O pessoal da secretária já resolveu essa parte","time":"28/01/2026 08:48:07"},{"role":"client","text":"*Thayanne Sales:* Vou lhe enviar o link de inscrição","time":"28/01/2026 08:48:22"},{"role":"client","text":"*Thayanne Sales:* Mas qual seria  o curso","time":"28/01/2026 08:48:28"},{"role":"client","text":"*Thayanne Sales:* ?","time":"28/01/2026 08:49:15"},{"role":"client","text":"*Thayanne Sales:* Olá Bom dia me chamo Thayanne Sales da Cidade Viva! \n","time":"29/01/2026 08:33:08"},{"role":"client","text":"Atendimento Finalizado!\n\nElvira Lima, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"29/01/2026 14:04:31"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"29/01/2026 14:04:32"},{"role":"client","text":"Elvira Lima, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"29/01/2026 14:19:33"}]$tag$, $tag$2026-01-26 14:59:40+00$tag$, FALSE, TRUE, 9, $tag$2026-03-01 16:46:57.607947+00$tag$, 10, 10, 10, 6, 9, 29, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upl