INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$be78741c-4f25-41ae-8409-213622291c4f$tag$, $tag$2026012700045$tag$, $tag$Ana Rute Coelho da Silva (5514991359645)$tag$, NULL, $tag$Thayanne Sales$tag$, $tag$[{"role":"agent","text":"*Thayanne Sales:* Olá Bom dia me chamo Thayanne Sales da Cidade Viva! \n","time":"27/01/2026 10:01:01","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Olá","time":"27/01/2026 10:16:19"},{"role":"agent","text":"*Thayanne Sales:* Olá, bom dia!! \n\nMe chamo Thayanne, sou do Setor de Relacionamento da *Faculdade Internacional Cidade Viva*.\n\n\nFicamos muito felizes com o seu interesse em um dos nossos cursos, mas percebi que *sua inscrição ainda não foi finalizada* 😕 \n\nAlguma situação em que posso te ajudar?\n\nOlha só, temos um *condição especial para você: fechando hoje a sua Graduação, paga somente R$ 99,00* reais na primeira mensalidade 💰\n\nEntão, corre e garanta já a sua vaga!\n\n👉Só responder a esta mensagem ;)","time":"27/01/2026 10:24:50","feedback":"🎯 Direcionamento: Excelente tentativa de conduzir o cliente ao fechamento."},{"role":"agent","text":"*Thayanne Sales:* Olá Bom dia! Tudo bom?\nQue alegria falar com você! 👋🏼\n\nVamos prosseguir com a sua matricula e garantir o desconto?","time":"28/01/2026 08:15:37","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Atendimento Finalizado!\n\nAna Rute Coelho da Silva, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"28/01/2026 10:29:18"}]$tag$, $tag$2026-01-27 10:01:01+00$tag$, FALSE, FALSE, 7.2, $tag$2026-03-01 16:46:57.607947+00$tag$, 10, 10, 7, 2, 7, 3, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
