INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$d4767657-e5ff-4224-8c8a-216a83b03b1e$tag$, $tag$2026012700047$tag$, $tag$Vagner André Koiavinski (5549988435052)$tag$, NULL, $tag$Thayanne Sales$tag$, $tag$[{"role":"client","text":"Oi, vim pelo Instagram e quero mais informações","time":"27/01/2026 10:02:56"},{"role":"client","text":"🌟 Bom dia Vagner André Koiavinski! Que alegria ter você aqui com a gente! 🙌","time":"27/01/2026 10:02:57"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"27/01/2026 10:03:01"},{"role":"client","text":"??","time":"27/01/2026 10:03:01"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"27/01/2026 10:03:02"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"27/01/2026 10:03:05"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"27/01/2026 10:03:09"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"27/01/2026 10:03:16"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"27/01/2026 10:03:22"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"27/01/2026 10:03:23"},{"role":"client","text":"Sim, concordo","time":"27/01/2026 10:03:41"},{"role":"client","text":"✅ Obrigado, Vagner André Koiavinski! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"27/01/2026 10:03:42"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"27/01/2026 10:03:46"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"27/01/2026 10:04:22"},{"role":"client","text":"Olá! Vagner André Koiavinski!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"27/01/2026 10:04:25"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"27/01/2026 10:04:29"},{"role":"client","text":"Saber sobre os cursos","time":"27/01/2026 10:05:08"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"27/01/2026 10:05:12"},{"role":"client","text":"Pós-Graduação","time":"27/01/2026 10:05:29"},{"role":"client","text":"Esses são os cursos de *Pós-Graduação* que temos disponíveis no momento:","time":"27/01/2026 10:05:35"},{"role":"client","text":"Ciência Política","time":"27/01/2026 10:05:59"},{"role":"client","text":"Quer compreender os fundamentos políticos a partir de uma cosmovisão cristã?\n 📘 Curso voltado para quem atua ou deseja atuar em política, gestão pública ou liderança institucional\n 📅 Início em agosto\n 💻 Estudo online e contextualizado\n","time":"27/01/2026 10:06:00"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"27/01/2026 10:06:04"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"27/01/2026 10:06:19"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"27/01/2026 10:06:20"},{"role":"client","text":"Ok","time":"27/01/2026 10:06:33"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Thayanne Sales","time":"27/01/2026 10:17:32"},{"role":"agent","text":"*Thayanne Sales:* &nbsp;Olá Bom dia! Tudo bom?\nQue alegria falar com você! 👋🏼\n\nVou lhe enviar as informações sobre o curso","time":"27/01/2026 10:17:45","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"agent","text":"*Thayanne Sales:* *Pós-Graduação em Formação Politica e Atuação Pública*\n\nNOTA MÁXIMA NO MEC\nPós-graduação com a maior avaliação junto ao MEC, conceito 05 estrelas.\n\nDURAÇÃO\nO curso tem duração de 16 meses.\n\nCARGA HORÁRIA\nNossa carga horária é de 480 h.\n\nDISCIPLINAS\nContamos com um total de 11 disciplinas.\n\nAULAS\nO curso é totalmente on-line e você pode assistir às aulas em qualquer dia e horário, pois ficarão gravadas dentro da plataforma.\n\nAVALIAÇÕES\nAs avaliações serão realizadas através de questões abertas, fechadas, fóruns e elaboração de textos. Todas as atividades serão realizadas dentro da plataforma educacional, assim, não é necessário ter um Polo da Faculdade em sua cidade.\n\nNÃO É NECESSÁRIO TCC\nDe acordo com a nova deliberação do MEC, a Resolução CNE/CES nº 1/2018, não há mais a obrigação de entrega de um TCC.","time":"27/01/2026 10:18:01","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* Formação Politica e Atuação Pública - DISCIPLINAS DO CURSO:\n\nBASE: COSMOVISÃO CRISTÃ\nCosmovisão Cristã e Política \nIdeologias Políticas Contemporâneas\nÉtica Cristã \n\nBASE: CIÊNCIA POLÍTICA\nTeorias políticas clássicas\nTeoria política reformacional\nPolítica e Ordem Jurídica \nCidadania e Ação Cívica \n\nBASE: ATUAÇÃO PÚBLICA\nPoder Executivo \nPoder Legislativo\nPoder Judiciário \n\nDISCIPLINA FACULTATIVA\nMentoria para Candidatos a Mandatos Eletivos - Marketing e Posicionamento\n\nObs: Professores sujeitos a alterações. ","time":"27/01/2026 10:18:05","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* O valor de investimento na Pós-graduação em Formação Politica e Atuação Pública  está em 16 mensalidades de *R$ 359,37*. Esse mês esta com condições especiais esta com 50% de desconto e as mensalidades ficam por R$ 179,68.\n\n\nNão temos taxa de matrícula. Ao pagar a primeira mensalidade hoje, as próximas serão devidas a partir do início das aulas, previsto para Abril/2026.\n\n*Mas lembrando que o desconto é de pontualidade  para pagamento até o dia 10 de cada mês, caso algum mês você pague fora desse período, naquele mês o valor vai ficar cheio. \n\n*Assim que fizer sua matricula e  efetuar o pagamento, me envia o comprovante de pagamento para eu poder da baixa no sistema.*","time":"27/01/2026 10:18:29","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Consegue me enviar os professores, curriculos e emendas","time":"27/01/2026 10:20:13"},{"role":"client","text":"Datas dad aulas","time":"27/01/2026 10:20:19"},{"role":"agent","text":"*Thayanne Sales:* Será em abril, mas a data ainda está sendo definida.","time":"27/01/2026 10:21:24","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* Ementa da Pós-Graduação em Ciência Política e Atuação Pública\n\nCosmovisão Cristã e Política\nEmenta: Esta disciplina visa apresentar os fundamentos da cosmovisão cristã para a compreensão da política e da atuação dos cristãos na esfera pública. A partir de uma análise das escrituras sagradas serão abordados temas como: o propósito de Deus para a criação e o governo humano; anatureza e a função do Estado; os princípios e valores cristãos para a política; os modelos e exemplos de líderes políticos na Bíblia; as relações entre a igreja e o Estado; os desafios e as oportunidades para os cristãos na política contemporânea. \n\nIdeologias Políticas Contemporâneas\nEmenta: Esta disciplina visa apresentar o conceito de cosmovisão cristã e sua relevância para a compreensão e a atuação dos cristãos na sociedade. A partir de uma análise bíblica, teológica e filosófica, serão abordados temas como: o que é cosmovisão e como ela influencia nossa forma de pensar e agir; quais são as características e os fundamentos da cosmovisão cristã; como a cosmovisão cristã se diferencia das demais cosmovisões; quais são as principais ideologias contemporâneas e como elas se relacionam com a cosmovisão cristã; como desenvolver uma postura crítica e transformadora diante das ideologias.\n\nÉtica Cristã\nEmenta: Esta disciplina visa apresentar os desafios éticos que os cristãos enfrentam na atualidade, diante de questões polêmicas e controversas que envolvem a vida humana, a família, a sexualidade, as drogas e a tecnologia. A partir de uma análise bíblica, teológica e filosófica, serão abordados temas como: o valor e a dignidade da vida humana desde a concepção até a morte natural; o plano de Deus para a família e o casamento; a crítica cristã à ideologia de gênero e à teoria queer; os efeitos das drogas na saúde física, mental e espiritual; os benefícios e os riscos da tecnologia para a sociedade e para a igreja. \n\nTeorias políticas clássicas\nEmenta: Esta disciplina visa apresentar os fundamentos da filosofia política, isto é, as reflexões filosóficas sobre a origem, a natureza, a finalidade e os problemas da vida em sociedade e das relações de poder. A partir de uma análise histórica e crítica, serão abordados temas como: o surgimento da filosofia política na Grécia antiga; as principais correntes e pensadores da filosofia política ocidental; as ideias e os conceitos-chave da filosofia política; as relações entre a filosofia política e outras áreas do conhecimento; os desafios e as perspectivas da filosofia política na atualidade. \n\nTeoria política reformacional\nEmenta: Esta disciplina visa apresentar as contribuições da tradição reformacional para a ciência política e a filosofia, a partir da análise do pensamento de Abraham Kuyper e Herman Dooyeweerd. Serão abordados temas como: o conceito de soberania das esferas e a abordagem social de Kuyper e a filosofia político-social de Dooyeweerd. Serão discutidas as críticas ao modernismo, ao historicismo e ao positivismo, destacando-se as implicações de uma teoria cristã para a política e sociedade. \n\nPolítica e Ordem Jurídica\nEmenta: Esta disciplina visa apresentar os conceitos básicos e as características dos regimes políticos, dos sistemas de governo, das formas de Estado e das formas de governo, bem como as noções essenciais de direito constitucional. A partir de uma análise histórica e comparativa, serão abordados temas como: o que são regimes políticos e quais os seus tipos (democrático, autoritário e totalitário); o que são sistemas de governo e quais os seus tipos (parlamentarismo, presidencialismo e semipresidencialismo); o que são formas de Estado e quais as suas tipos (unitário, federal e confederal); o que são formas de governo e quais os seus tipos (monarquia e república); o que é direito constitucional e quais os seus princípios, normas e instituições. \n\nCidadania e Ação Cívica\nEmenta: Esta disciplina visa apresentar os conceitos e as práticas de educação política, políticas públicas, exercício da cidadania, combate à corrupção e transformação social, bem como as suas inter-relações e implicações para a sociedade brasileira. A partir de uma perspectiva crítica e propositiva, serão abordados temas como: o que é educação política e qual a sua importância para a formação do cidadão; o que são políticas públicas e como elas se relacionam com os direitos humanos e sociais; o que é exercício da cidadania e quais os seus direitos e deveres; o que é corrupção e quais os seus impactos na democracia e no desenvolvimento; o que é uma visão de transformação social e quais os seus fundamentos éticos e espirituais. \n\nPoder Executivo\nEmenta: Esta disciplina visa apresentar os princípios e as práticas de liderança cristã no Poder Executivo, tanto em nível federal, estadual quanto municipal, bem como os desafios e as oportunidades que se apresentam para os cristãos que exercem ou pretendem exercer cargos públicos nessa esfera. A partir de uma perspectiva bíblica, histórica e ética, serão abordados temas como: o que é liderança cristã e quais as suas características, valores e responsabilidades; o que é Poder Executivo e quais as suas funções, estruturas e competências; quais os desafios que os líderes cristãos enfrentam no Poder Executivo, tais como a corrupção, a secularização, a pluralidade religiosa, a prestação de contas, entre outros; quais as oportunidades que os líderes cristãos têm no Poder Executivo, tais como a promoção de políticas públicas virtuosas, da justiça social, a defesa da vida e da família, o testemunho do evangelho, entre outros. \n\nPoder Legislativo\nEmenta: Esta disciplina visa apresentar os princípios e as práticas de liderança cristã no Poder Legislativo, tanto em nível federal, estadual quanto municipal, bem como os desafios e as oportunidades que se apresentam para os cristãos que exercem ou pretendem exercer cargos públicos nessa esfera. A partir de uma perspectiva bíblica, histórica e ética, serão abordados temas como: o que é liderança cristã e quais as suas características, valores e responsabilidades; o que é Poder Legislativo e quais as suas funções, estruturas e competências; quais os desafios que os líderes cristãos enfrentam no Poder Legislativo, tais como a corrupção, a secularização, a pluralidade religiosa, a representatividade, entre outros; quais as oportunidades que os líderes cristãos têm no Poder Legislativo, tais como a elaboração de leis justas, a fiscalização do Poder Executivo, a defesa da vida e da família, o testemunho do evangelho, entre outros. \n\nPoder Judiciário\nEmenta: Esta disciplina visa apresentar os princípios e as práticas de liderança cristã no Poder Judiciário, bem como os desafios e as oportunidades que se apresentam para os cristãos que exercem ou pretendem exercer cargos públicos ou a advocacia nessa esfera. A partir de uma perspectiva bíblica, histórica e ética, serão abordados temas como: o que é liderança cristã e quais as suas características, valores e responsabilidades; o que é Poder Judiciário e quais as suas funções, estruturas e competências; quais os desafios que os líderes cristãos enfrentam no Poder Judiciário, tais como o ativismo judicial, a secularização, a pluralidade religiosa, o laicismo estatal, a representatividade, entre outros; quais as oportunidades que os líderes cristãos têm no Poder Judiciário, tais como a tais como a promoção da justiça, a defesa dos direitos humanos, a aplicação da lei, o testemunho do evangelho, entre outros. \n\n\nMentoria para Candidatos a Mandatos Eletivos - Marketing e Posicionamento\nEmenta: Esta disciplina tem como objetivo capacitar os alunos a planejar e executar estratégias de marketing e posicionamento para candidatos a mandatos eletivos. Os conteúdos abordados incluem: conceitos e ferramentas de marketing político, análise do cenário eleitoral, definição do público-alvo, construção da imagem e da mensagem do candidato, uso de mídias tradicionais e digitais, monitoramento e avaliação de resultados.","time":"27/01/2026 10:22:27","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* Ementa da Pós-Graduação em Ciência Política e Atuação Pública\n\nCosmovisão Cristã e Política\nEmenta: Esta disciplina visa aprese