INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$a3025138-cb1f-4f8e-8197-8ac9ab91ec32$tag$, $tag$2026012700083$tag$, $tag$Maysa Fontoura (5562981618425)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Quero mais informações sobre a pós em Educação Cristã Clássica","time":"27/01/2026 11:56:09"},{"role":"client","text":"🌟 Bom dia Maysa Fontoura! Que alegria ter você aqui com a gente! 🙌","time":"27/01/2026 11:56:10"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"27/01/2026 11:56:14"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"27/01/2026 11:56:18"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"27/01/2026 11:56:22"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"27/01/2026 11:56:28"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"27/01/2026 11:56:34"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"27/01/2026 11:56:35"},{"role":"client","text":"Sim, concordo","time":"27/01/2026 11:56:48"},{"role":"client","text":"✅ Obrigado, Maysa Fontoura! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"27/01/2026 11:56:49"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"27/01/2026 11:56:54"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"27/01/2026 11:57:28"},{"role":"client","text":"Olá! Maysa Fontoura!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"27/01/2026 11:57:29"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"27/01/2026 11:57:33"},{"role":"client","text":"Saber sobre os cursos","time":"27/01/2026 11:57:49"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"27/01/2026 11:57:54"},{"role":"client","text":"Pós-Graduação","time":"27/01/2026 11:58:12"},{"role":"client","text":"Esses são os cursos de *Pós-Graduação* que temos disponíveis no momento:","time":"27/01/2026 11:58:16"},{"role":"client","text":"Educação Cristã Clássica","time":"27/01/2026 11:58:28"},{"role":"client","text":"Formação exclusiva para educadores e líderes que desejam ensinar com base na tradição cristã clássica.\n\n 📚 Cosmovisão cristã sólida\n 📌 Leituras fundamentais do pensamento ocidental\n 🧭 Formação para escolas cristãs ou ministérios educacionais\n 🗓️ Matrículas abertas para agosto","time":"27/01/2026 11:58:29"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"27/01/2026 11:58:33"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"27/01/2026 11:58:51"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"27/01/2026 11:58:52"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"27/01/2026 11:59:17"},{"role":"agent","text":"*Karina Pimentel:* *Pós-graduação em Educação Cristã Clássica*.\n\n*NOTA MÁXIMA NO MEC*\nPós-graduação com a maior avaliação junto ao MEC, conceito 05 estrelas.\n\n*DURAÇÃO*\nO curso tem duração de 16 meses.\n\n*CARGA HORÁRIA*\nNossa carga horária é de 400h.\n\n*DISCIPLINAS*\nContamos com um total de 10 disciplinas.\n\n*AULAS*\nO curso é totalmente on-line e você pode assistir às aulas em qualquer dia e horário, pois ficarão gravadas dentro da plataforma.\n\n*AVALIAÇÕES*\nAs avaliações serão realizadas através de questões abertas, fechadas, fóruns e elaboração de textos. Todas as atividades serão realizadas dentro da plataforma educacional, assim, não é necessário ter um Polo da Faculdade em sua cidade.\n\n*NÃO É NECESSÁRIO TCC*\nDe acordo com a nova deliberação do MEC, a Resolução CNE/CES nº 1/2018, não há mais a obrigação de entrega de um TCC.","time":"27/01/2026 11:59:36","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Bom dia","time":"27/01/2026 11:59:37"},{"role":"agent","text":"*Karina Pimentel:* O valor de investimento na Pós-graduação em Educação Cristã Clássica está em 16 mensalidades de *R$ 479,16*. \n\nNão temos taxa de matrícula. Ao pagar a primeira mensalidade hoje, as próximas serão devidas a partir do início das aulas, previsto para Abril de 2026!","time":"27/01/2026 11:59:44","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* Estamos com uma oferta especial essa semana, 20% de desconto nas mensalidades! 🤩\nMensalidades ficarão no valor de R$ 383,33.\nVamos garantir a sua vaga? 😊","time":"27/01/2026 11:59:53","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Pra quando é a próxima turma?","time":"27/01/2026 12:00:47"},{"role":"agent","text":"*Karina Pimentel:* Abril","time":"27/01/2026 14:07:05","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* E a próxima em Setembro!","time":"27/01/2026 14:07:17","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:*  Ficou alguma dúvida? O que está faltando para você dar esse passo e ingressar no curso? Tenho certeza de que será transformador em sua vida. 😊","time":"27/01/2026 19:21:02","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Atendimento Finalizado!\n\nMaysa Fontoura, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"29/01/2026 10:03:09"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"29/01/2026 10:03:10"},{"role":"client","text":"Maysa Fontoura, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"29/01/2026 10:18:11"}]$tag$, $tag$2026-01-27 11:56:09+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:46:57.607947+00$tag$, 10, 10, 10, 2, 9, 6, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attemp