INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$69356006-85d9-4542-bdcc-93132b08e7f0$tag$, $tag$2026012700118$tag$, $tag$Duellaynne (5561991126700)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Boa tarde","time":"27/01/2026 13:45:46"},{"role":"client","text":"🌟 Boa tarde Duellaynne! Que alegria ter você aqui com a gente! 🙌","time":"27/01/2026 13:45:47"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"27/01/2026 13:45:51"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"27/01/2026 13:45:55"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"27/01/2026 13:46:03"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"27/01/2026 13:48:14"},{"role":"client","text":"Olá! Duellaynne!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"27/01/2026 13:48:16"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"27/01/2026 13:48:19"},{"role":"client","text":"Saber sobre os cursos","time":"27/01/2026 13:48:34"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"27/01/2026 13:48:38"},{"role":"client","text":"Pós-Graduação","time":"27/01/2026 13:48:48"},{"role":"client","text":"Esses são os cursos de *Pós-Graduação* que temos disponíveis no momento:","time":"27/01/2026 13:48:53"},{"role":"client","text":"Educação Cristã Clássica","time":"27/01/2026 13:49:17"},{"role":"client","text":"Formação exclusiva para educadores e líderes que desejam ensinar com base na tradição cristã clássica.\n\n 📚 Cosmovisão cristã sólida\n 📌 Leituras fundamentais do pensamento ocidental\n 🧭 Formação para escolas cristãs ou ministérios educacionais\n 🗓️ Matrículas abertas para agosto","time":"27/01/2026 13:49:19"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"27/01/2026 13:49:23"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"27/01/2026 13:50:10"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"27/01/2026 13:50:11"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"27/01/2026 14:02:13"},{"role":"agent","text":"*Karina Pimentel:* *Pós-graduação em Educação Cristã Clássica*.\n\n*NOTA MÁXIMA NO MEC*\nPós-graduação com a maior avaliação junto ao MEC, conceito 05 estrelas.\n\n*DURAÇÃO*\nO curso tem duração de 16 meses.\n\n*CARGA HORÁRIA*\nNossa carga horária é de 400h.\n\n*DISCIPLINAS*\nContamos com um total de 10 disciplinas.\n\n*AULAS*\nO curso é totalmente on-line e você pode assistir às aulas em qualquer dia e horário, pois ficarão gravadas dentro da plataforma.\n\n*AVALIAÇÕES*\nAs avaliações serão realizadas através de questões abertas, fechadas, fóruns e elaboração de textos. Todas as atividades serão realizadas dentro da plataforma educacional, assim, não é necessário ter um Polo da Faculdade em sua cidade.\n\n*NÃO É NECESSÁRIO TCC*\nDe acordo com a nova deliberação do MEC, a Resolução CNE/CES nº 1/2018, não há mais a obrigação de entrega de um TCC.","time":"27/01/2026 14:02:41","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* O valor de investimento na Pós-graduação em Educação Cristã Clássica está em 16 mensalidades de *R$ 479,16*. \n\nNão temos taxa de matrícula. Ao pagar a primeira mensalidade hoje, as próximas serão devidas a partir do início das aulas, previsto para Abril de 2026!","time":"27/01/2026 14:02:51","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* Estamos com uma oferta especial essa semana, 20% de desconto nas mensalidades! 🤩\nMensalidades ficarão no valor de R$ 383,33.\nVamos garantir a sua vaga? 😊","time":"27/01/2026 14:02:57","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"agent","text":"*Karina Pimentel:* 🎁 Cupom de Desconto ECC: BOLSA20\n\n📌 Realize sua matrícula no link: bit.ly/InscricaoPosECC2024\n\n✅ Assim que você preencher os seus dados, o sistema disponibilizará o seu contrato para aceitação e o pagamento da primeira parcela, que pode ser feito por cartão ou boleto.","time":"27/01/2026 14:03:13","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:*  Ficou alguma dúvida? O que está faltando para você dar esse passo e ingressar no curso? Tenho certeza de que será transformador em sua vida. 😊","time":"27/01/2026 19:20:31","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Obrigada.","time":"27/01/2026 20:35:08"},{"role":"client","text":"Vou fazer minha inscrição","time":"27/01/2026 20:35:20"},{"role":"agent","text":"*Karina Pimentel:* Bom dia!","time":"28/01/2026 08:38:19","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Qualquer duvida estou a disposição!","time":"28/01/2026 08:38:30","feedback":"🚩 Fechamento Ausente: O contato está terminando. Sempre faça um convite para o próximo passo."},{"role":"client","text":"Atendimento Finalizado!\n\nDuellaynne, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"29/01/2026 10:05:49"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"29/01/2026 10:05:52"},{"role":"client","text":"Duellaynne, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"29/01/2026 10:20:54"}]$tag$, $tag$2026-01-27 13:45:46+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:46:57.607947+00$tag$, 10, 10, 10, 2, 9, 7, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
