INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$b7b93271-367b-4341-a652-887c1d9963b4$tag$, $tag$2026012700130$tag$, $tag$José (5521964293904)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"agent","text":"*Karina Pimentel:* Olá Boa tarde me chamo Karina Pimentel da Cidade Viva! \n","time":"27/01/2026 14:12:06","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Olá","time":"27/01/2026 14:18:44"},{"role":"client","text":"Boa tarde","time":"27/01/2026 14:18:52"},{"role":"client","text":"Sim","time":"27/01/2026 14:18:56"},{"role":"agent","text":"*Karina Pimentel:* Olá!","time":"27/01/2026 14:19:16","feedback":"🤝 Humanização & Rapport: Ótimo início. Lembre-se de primeiro entender o momento do cliente antes de qualquer script."},{"role":"agent","text":"*Karina Pimentel:* Sr Fabricio pediu para contata-lo! ","time":"27/01/2026 14:19:31","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Seria sobre Teologia Ead?","time":"27/01/2026 14:19:42","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Sim sim","time":"27/01/2026 15:09:25"},{"role":"client","text":"Isso","time":"27/01/2026 15:09:25"},{"role":"client","text":"Podemos continuar demorei a responder por causa do trabalho","time":"27/01/2026 15:09:43"},{"role":"client","text":"Mais pode prosseguir por gentileza","time":"27/01/2026 15:09:56"},{"role":"agent","text":"*Karina Pimentel:* Clato!","time":"27/01/2026 15:39:59","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Claro!","time":"27/01/2026 15:40:05","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* A nossa *Graduação em Teologia EAD* é Bacharelado reconhecido pelo MEC ( *bit.ly/3LlEgJS* ), com a duração de 3 anos.\n\nNo formato EAD, as aulas são ao vivo e gravadas e ficam à disposição do aluno no Ambiente Virtual de Aprendizagem, para assistir no seu tempo. As aulas ao vivo terão dia e horário definidos previamente e poderão ser assistidas posteriormente, pois ficarão gravadas.\n\nO aluno tem acesso aos materiais disponibilizados por nossos professores, tem encontros remotos com tutores, através da Plataforma Virtual da FICV (Plataforma Moodle), além de contar com materiais de apoio acadêmico-científico.","time":"27/01/2026 15:40:21","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:*  Graduação EAD em Teologia por apenas R$ 399,70/mês! 🤩 Aproveite a condição especial: 20% de desconto na pontualidade durante toda a graduação, reduzindo o valor para R$ 319,76 por mês! 🎉 Usando o cupom *BOLSA20*\n\n✨ Sem taxa de matrícula! A primeira mensalidade é paga no ato da inscrição, e a próxima apenas no mês de início das aulas.\n\n🤑 Valor promocional: Semestralidade por R$ 1.918,56!\n\n⚠ Atenção: O valor mensal pode variar de acordo com a data de matrícula:\n\nMatrículas realizadas até em JANEIRO: 6 mensalidades de R$ 319,76 = R$ 1.918,56\nMatrículas realizadas até em FEVEREIRO: 5 mensalidades de R$ 383,71 = R$ 1.918,56\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 479,64 = R$ 1.918,56\n\n🗓️ Início das aulas: Fevereiro de 2026 📚💻","time":"27/01/2026 15:40:45","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* ✅ PROCEDIMENTO DE MATRÍCULA:\n\nRealize a matrícula de acordo com a sua forma de ingresso, basta acessar o link correspondente abaixo:\n\n1 - Aproveitamento do ENEM:\nbit.ly/FICV-Enem\n\n2 - Vestibular Agendado:\nbit.ly/FICV-Vestibular\n\n3 - Seleção de Graduados:\nbit.ly/FICV-Graduados\n\n📝 Após preencher seus dados, o sistema disponibilizará o pagamento da primeira parcela e o contrato para aceite. Não há cobrança de matrícula.😊","time":"27/01/2026 15:41:12","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Ok","time":"27/01/2026 17:13:45"},{"role":"client","text":"Inscrição feita","time":"27/01/2026 17:51:22"},{"role":"client","text":"Boa tarde","time":"28/01/2026 17:46:33"},{"role":"client","text":"Fiz a minha inscrição","time":"28/01/2026 17:46:50"},{"role":"client","text":"Pastor Fabrício havia me falado que viria um boleto para pagamento de 5 dias uteis","time":"28/01/2026 17:47:34"},{"role":"client","text":"Até o momento hoje não recebi ainda sendo já realizei minha inscrição","time":"28/01/2026 17:47:54"},{"role":"agent","text":"*Karina Pimentel:* Benção!\n","time":"28/01/2026 18:04:46","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Qual nome completo por gentileza?","time":"28/01/2026 18:04:58","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"José Carlos Figueiredo santana","time":"28/01/2026 18:05:36"},{"role":"agent","text":"*Karina Pimentel:* Bom dia!","time":"29/01/2026 08:24:48","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Tudo bem, Sr José?","time":"29/01/2026 08:24:58","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{